static inline int em_check_traffic_rate(int teid, int payload_len) {
  // Assume we have a global variable 'traffic_rates' to store the traffic rates for each TEID
  if (teid in traffic_rates.keys()) {
    traffic_rates[teid] += payload_len
    if (time.time() - last_update[teid] > 1) { // Check rate every second
      rate = traffic_rates[teid] / (time.time() - last_update[teid])
      if rate > threshold:
        return 1
      else:
        return 0
    }
  } else {
    // Initialize new TEID with zero traffic rate and current time as last update time
    traffic_rates[teid] = 0
    last_update[teid] = time.time()
  }
}
